// src/components/PanelCliente.js
import React, { useState, useEffect } from 'react';
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

// Definimos las coordenadas fuera del componente para evitar el warning de dependencias
const COORDS_LOCAL = { lat: -26.8083, lon: -65.2176 };

const PanelCliente = () => {
  const [ofertas, setOfertas] = useState([]);
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  const [distanciaReal, setDistanciaReal] = useState(0);

  useEffect(() => {
    // 1. Cargar Ofertas
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acc = [];
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      acc = [...acc, ...ofs.map(o => ({ ...o, nombreLocal: l.nombre, localId: l.id }))];
    });
    setOfertas(acc);

    // 2. Obtener ubicación
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const d = calcularDistanciaReal(
            pos.coords.latitude, 
            pos.coords.longitude,
            COORDS_LOCAL.lat, 
            COORDS_LOCAL.lon
          );
          setDistanciaReal(d);
        },
        (err) => console.warn("Ubicación denegada o no disponible"),
        { enableHighAccuracy: true }
      );
    }
  }, []); // El array vacío ahora es correcto porque COORDS_LOCAL es estática

  const handlePagoExitoso = (totalPagado) => {
    const nuevoPedido = { 
      id: `PED-${Date.now()}`, 
      total: totalPagado, 
      distancia: distanciaReal.toFixed(2) 
    };
    setPedidos([nuevoPedido, ...pedidos]);
    setCart([]);
  };

  return (
    <div style={{ display: 'flex', gap: '30px', padding: '40px 5%', background: '#f8fafc', minHeight: '100vh' }}>
      <div style={{ flex: 1 }}>
        <h2 style={{color: '#1e293b', marginBottom: '20px'}}>Ofertas Cercanas</h2>
        <div style={gridStyle}>
          {ofertas.map(o => (
            <div key={o.id} style={cardStyle}>
              {o.imagen && <img src={o.imagen} style={imgStyle} alt="" />}
              <div style={{padding: '15px'}}>
                <small style={{color: '#e67e22', fontWeight: 'bold'}}>{o.nombreLocal}</small>
                <h4 style={{margin: '5px 0'}}>{o.producto}</h4>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                  <span style={{fontWeight: 'bold', fontSize: '1.2rem'}}>${o.precioNuevo}</span>
                  <button onClick={() => setCart([...cart, o])} style={btnAddToCart}>+</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div style={{ width: '380px' }}>
        {cart.length > 0 && (
          <Carrito 
            cart={cart} 
            setCart={setCart} 
            distanciaReal={distanciaReal} 
            onCheckout={handlePagoExitoso} 
          />
        )}
        
        {pedidos.length > 0 && (
          <div style={{ marginTop: '20px' }}>
            <h3 style={{fontSize: '1rem', color: '#64748b'}}>Seguimiento Actual</h3>
            {pedidos.map(p => <SeguimientoPedido key={p.id} pedido={p} />)}
          </div>
        )}
      </div>
    </div>
  );
};

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const cardStyle = { background: 'white', borderRadius: '15px', overflow: 'hidden', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '140px', objectFit: 'cover' };
const btnAddToCart = { background: '#1e293b', color: 'white', border: 'none', width: '35px', height: '35px', borderRadius: '10px', cursor: 'pointer', fontSize: '1.2rem' };

export default PanelCliente;
